const budgets  = $('Supabase — Obtener usuarios activos del mes').all();
const expenses = $('Supabase — Obtener gastos acumulados').all();

// Agrupar gastos por usuario
const expensesByUser = {};
for (const exp of expenses) {
  const uid = exp.json.user_id;
  if (!expensesByUser[uid]) expensesByUser[uid] = 0;
  expensesByUser[uid] += Number(exp.json.amount);
}

// Calcular estado de cada usuario
const results = [];
for (const budget of budgets) {
  const b    = budget.json;
  const uid  = b.user_id;
  const spent = expensesByUser[uid] || 0;
  const income = Number(b.income);
  const days_elapsed = 15;
  const days_in_month = new Date(new Date().getFullYear(), new Date().getMonth() + 1, 0).getDate();
  const expected_spend = income * (days_elapsed / days_in_month);

  // Ratio: gasto real vs gasto esperado a la mitad del mes
  // < 0.5 = muy bien, 0.5-0.8 = bien, > 0.8 = cuidado
  const ratio = income > 0 ? spent / expected_spend : 1;

  const is_doing_well = ratio < 0.80;

  // Tipo de logro
  let achievement_type = null;
  if (ratio < 0.50) achievement_type = 'mid_month_excellent';
  else if (ratio < 0.80) achievement_type = 'mid_month_ok';

  if (achievement_type) {
    results.push({
      user_id:          uid,
      income,
      spent,
      ratio:            Math.round(ratio * 100) / 100,
      is_doing_well,
      achievement_type,
      remaining:        Math.max(income - spent, 0),
      pct_spent:        Math.round(ratio * 100)
    });
  }
}

return results.map(r => ({ json: r }));

